create table public.member_consents (id uuid primary key default gen_random_uuid(),organization_id uuid not null references public.organizations(id) on delete cascade,member_profile_id uuid not null references public.member_profiles(id) on delete cascade,consent_type text not null check(consent_type in('communications','data_processing','photo_rights')),granted boolean not null,recorded_at timestamptz not null default now(),recorded_by uuid references auth.users(id),unique(organization_id,member_profile_id,consent_type));
create table public.data_subject_requests (id uuid primary key default gen_random_uuid(),organization_id uuid not null references public.organizations(id) on delete cascade,member_profile_id uuid references public.member_profiles(id) on delete set null,request_type text not null check(request_type in('export','deletion','correction')),status text not null default 'open' check(status in('open','in_progress','completed','rejected')),notes text,requested_at timestamptz not null default now(),resolved_at timestamptz,resolved_by uuid references auth.users(id));
create table public.retention_policies (id uuid primary key default gen_random_uuid(),organization_id uuid not null references public.organizations(id) on delete cascade,data_type text not null,retention_days integer not null check(retention_days>0),active boolean not null default true,unique(organization_id,data_type));
create table public.security_events (id uuid primary key default gen_random_uuid(),organization_id uuid references public.organizations(id) on delete cascade,event_type text not null,severity text not null check(severity in('info','warning','critical')),metadata jsonb not null default '{}',created_at timestamptz not null default now());
alter table public.member_consents enable row level security;alter table public.data_subject_requests enable row level security;alter table public.retention_policies enable row level security;alter table public.security_events enable row level security;
create policy "managers manage consents" on public.member_consents for all using(public.can_manage_organization(organization_id)) with check(public.can_manage_organization(organization_id));create policy "managers manage requests" on public.data_subject_requests for all using(public.can_manage_organization(organization_id)) with check(public.can_manage_organization(organization_id));create policy "admins manage retention" on public.retention_policies for all using(public.can_manage_organization(organization_id)) with check(public.can_manage_organization(organization_id));create policy "admins read security events" on public.security_events for select using(public.can_manage_organization(organization_id));
